// Filter rows that still need action - i.e. not already closed/booked
const rows = $input.all();

const DONE_STATUSES = ['Meeting Booked', 'Not Interested - Closed', 'Client Won'];

const activeRows = rows.filter(r => {
  const connStatus = r.json['Connection Status'] || '';
  const convStatus = r.json['Conversation Status'] || '';

  // Must have actually had a connection request sent (or already connected)
  const wasSent = connStatus === 'Connection Sent' || connStatus === 'Connected';

  // Skip anything already finished
  const isDone = DONE_STATUSES.includes(convStatus);

  return wasSent && !isDone;
});

return activeRows.map(r => ({ json: r.json }));

const chatData = $json;
const chatItems = chatData.items || [];

const providerId = $('Process One By One').item.json['Provider ID'];

const matchedChat = chatItems.find(
  chat => chat.attendee_provider_id === providerId
);

return [{
  json: {
    ...$('Process One By One').item.json,
    chat_id: matchedChat?.id || null,
    chat_exists: !!matchedChat
  }
}];

const prospect = $('Extract Chat ID').item.json;
const messagesData = $json;
const messages = (messagesData.items || []).slice().reverse(); // oldest first

const myProviderId = '************************'; // YOUR LinkedIn provider id

const conversation = messages.map(m => ({
  from: m.sender_id === myProviderId || m.is_sender ? 'me' : 'prospect',
  text: m.text || m.body || '',
  time: m.timestamp || m.created_at || ''
}));

const lastMsg = conversation[conversation.length - 1] || {};
const hasReplied = lastMsg.from === 'prospect';
const noMessagesAtAll = conversation.length === 0;

return [{
  json: {
    ...prospect,
    full_conversation: conversation,
    last_message_from: lastMsg.from || '',
    last_message_text: lastMsg.text || '',
    has_replied: hasReplied,
    is_first_message: noMessagesAtAll,
    message_count: conversation.length
  }
}];

const events = ($json.items || []);
const bookedSlots = events.map(e => ({
  start: new Date(e.start?.dateTime || e.start?.date),
  end: new Date(e.end?.dateTime || e.end?.date)
}));

const availableSlots = [];
const now = new Date();

for (let day = 1; day <= 7 && availableSlots.length < 3; day++) {
  const date = new Date(now);
  date.setDate(date.getDate() + day);
  if (date.getDay() === 0 || date.getDay() === 6) continue;

  for (let hour = 9; hour <= 17 && availableSlots.length < 3; hour++) {
    const slotStart = new Date(date);
    slotStart.setHours(hour, 0, 0, 0);
    const slotEnd = new Date(slotStart);
    slotEnd.setMinutes(30);

    const isBooked = bookedSlots.some(b => slotStart < b.end && slotEnd > b.start);

    if (!isBooked) {
      availableSlots.push({
        display: slotStart.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' }) +
                 ' at ' + slotStart.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
        iso: slotStart.toISOString()
      });
    }
  }
}

return [{
  json: {
    ...$('Has Prospect Replied?').item.json,
    available_slots: availableSlots
  }
}];

const aiRaw = $json.choices?.[0]?.message?.content || '{}';
let aiReply;
try {
  const match = aiRaw.match(/\{[\s\S]*\}/);
  aiReply = JSON.parse(match ? match[0] : '{}');
} catch(e) {
  aiReply = { message: "Thanks for your message! Let me follow up shortly.", intent: 'CONTINUE', budget_mentioned: '', meeting_agreed: false };
}

const prospect = $('Find Free Slots').item.json;

return [{
  json: {
    ...prospect,
    ai_message: aiReply.message || '',
    intent: (aiReply.intent || 'CONTINUE').toUpperCase(),
    budget_mentioned: aiReply.budget_mentioned || '',
    meeting_agreed: aiReply.meeting_agreed === true
  }
}];

